module johnson_counter(clk, reset, q);

    input  clk;  
    input  reset;  
    output  [4-1:1-1] q;  
    reg    [3:0] q; 
    initial q = 0;

    always @(posedge clk)
          begin
            if (reset) 
                q <= 0;
            else
                q <= {q[2:0], ~q[3]};
          end  

endmodule
